def seed_if_empty(ds) -> bool:
    """DB의 attendance_records가 비어있을 때만 데모 데이터 삽입."""
    if ds.get_attendance_records():
        return False

    # 1. 훈련생 프로필
    for name, cohort, course, instructor, enrolled_at in TRAINEE_PROFILES:
        ds.upsert_trainee({
            "name": name, "cohort": cohort, "course": course,
            "instructor": instructor, "enrolled_at": enrolled_at,
        })

    # 2. 출결 레코드
    import pandas as pd
    df = pd.DataFrame(ATTENDANCE_RECORDS, columns=["name", "date", "status"])
    ds.save_attendance_records(df, COURSE, COHORT)

    # 3. 위험도 히스토리
    for row in RISK_HISTORY:
        ds.insert_risk_history(*row)

    return True


